    ret_token = build_type_token(ret_type, refs)
    code = f"{method['name']}({', '.join(parts)}): {ret_token} {{ throw new Error('not implemented'); }}"
    template_refs = [{"placeholder": k, "typeIdentifier": v} for k, v in refs.items()]
